#!/usr/bin/env bash
set -euo pipefail; source "$(dirname "$0")/lib/android-test.sh"; serial=RFCT90AEEFA; package=org.archphene.linux.p28ae847c2c818246c42d2ba69544759e; activity=org.archphene.linux.kcalc.MainActivity; capture_seconds=5; disable_privacy=false; while (($#)); do case "$1" in --serial)serial="${2:?}";shift 2;;--package)package="${2:?}";shift 2;;--activity)activity="${2:?}";shift 2;;--capture-seconds)capture_seconds="${2:?}";shift 2;;--temporarily-disable-microphone-privacy)disable_privacy=true;shift;;*)archphene_die "unknown argument: $1";;esac;done; ((capture_seconds>=1 && capture_seconds<=30)) || archphene_die 'capture seconds must be 1..30'; archphene_test_init "$serial"; dump="$(archphene_adb_run shell dumpsys package "$package")"; [[ "$dump" == *android.permission.RECORD_AUDIO* && "$dump" == *'android.permission.RECORD_AUDIO: granted=true'* ]] || archphene_die 'RECORD_AUDIO is not declared and granted'; privacy=false; archphene_adb_run shell dumpsys audio | grep -q 'mic mute .*from system=true' && privacy=true; if [[ "$privacy" == true && "$disable_privacy" == false ]];then archphene_die 'device-wide microphone privacy is enabled';fi; restore(){ archphene_adb_run shell am force-stop "$package" >/dev/null 2>&1 || true; [[ "$privacy" == true ]] && archphene_adb_run shell cmd sensor_privacy enable 0 microphone >/dev/null 2>&1 || true;};trap restore EXIT; [[ "$privacy" == false ]] || archphene_adb_run shell cmd sensor_privacy disable 0 microphone; archphene_adb_run logcat -c; archphene_adb_run shell am start -W -n "$package/$activity" >/dev/null; log="$(archphene_wait_log 'Android AAudio microphone capture started' 20 'ArchpheneAudio:I ArchpheneBridge:I AndroidRuntime:E *:S')"; for check in 'Private PulseAudio microphone bridge ready' 'Linux microphone stream attached' 'Android AAudio microphone capture started';do [[ "$log" == *"$check"* ]] || archphene_die "missing audio evidence: $check";done; root="/data/data/$package"; cmd="LD_LIBRARY_PATH=$root/files/linux-runtime/lib PULSE_SERVER=unix:$root/cache/pa/s timeout $capture_seconds $root/files/linux-runtime/lib/libarchphene_pulse_probe.so --record --raw --device=archphene_input --rate=48000 --channels=1 > $root/cache/archphene-microphone-test.raw"; set +e; archphene_adb_run shell run-as "$package" sh -c "'$cmd'" >/dev/null 2>&1; rc=$?;set -e; [[ $rc == 124 ]] || archphene_die "capture client exited $rc"; values="$(archphene_adb_run shell run-as "$package" od -An -tu1 -v cache/archphene-microphone-test.raw)"; bytes="$(wc -w <<<"$values")"; nonzero="$(tr -s ' ' '\n' <<<"$values"|grep -vc '^0$' || true)"; ((bytes>=48000*2*capture_seconds*8/10 && nonzero>0)) || archphene_die "capture invalid: $bytes bytes, $nonzero nonzero"; archphene_note "Android microphone bridge passed on $serial: $bytes bytes, $nonzero nonzero."
